# Error budget calculation & burn-rate alerting
from datetime import datetime, timedelta
import math

class ErrorBudget:
    def __init__(self, slo=99.9, window_days=30):
        self.slo, self.window = slo, timedelta(days=window_days)
        self.allowed_bad = 1 - slo/100
        self.errors, self.total = [], []

    def record(self, ok):
        now = datetime.now()
        self.errors.append(now) if not ok else None
        self.total.append(now)
        self._trim()

    def _trim(self):
        cutoff = datetime.now() - self.window
        self.errors = [e for e in self.errors if e > cutoff]
        self.total = [t for t in self.total if t > cutoff]

    def consumed(self):
        return len(self.errors) / len(self.total) if self.total else 0

    def remaining(self):
        return max(0, self.allowed_bad - self.consumed())

    def remaining_time(self):
        rate = self.consumed() / min(self.window.total_seconds(),
            (datetime.now() - self.total[0]).total_seconds() if self.total else 1)
        if rate <= 0: return self.window.total_seconds()
        return self.remaining() / rate

    def burn_rate(self, since):
        period_errors = sum(1 for e in self.errors if e > since)
        period_total = sum(1 for t in self.total if t > since)
        if period_total == 0: return 0
        actual_bad = period_errors / period_total
        return actual_bad / self.allowed_bad

# Burn-rate alert evaluation
def evaluate_burn_alerts(budget):
    now = datetime.now()
    alerts = {
        "critical_2h": budget.burn_rate(now - timedelta(hours=2)) > 14.4,
        "warning_6h": budget.burn_rate(now - timedelta(hours=6)) > 6,
        "watch_3d":  budget.burn_rate(now - timedelta(days=3)) > 1
    }
