# Metrics aggregation with cardinality management
from collections import defaultdict
import threading, time

class MetricsRegistry:
    MAX_LABELS = 20  # cardinality budget per metric

    def __init__(self):
        self._data = defaultdict(list)
        self._lock = threading.Lock()

    def record(self, name, val, labels=None):
        with self._lock:
            self._data[(name, frozenset((labels or {}).items()))].append((time.time(), val))

    def _aggregate(self, series, fn, since):
        vals = [v for t,v in series if t > since]
        return fn(vals) if vals else 0

    def query(self, name, duration=300, agg="avg"):
        since = time.time() - duration
        fn = {"avg": lambda vs: sum(vs)/len(vs), "p99": lambda vs: sorted(vs)[int(len(vs)*0.99)],
              "count": len, "sum": sum}[agg]
        return [{"labels": dict(k[1]), "value": self._aggregate(v, fn, since)}
                for k,v in self._data.items() if k[0] == name]

# Sampling: structured log sampling
class SampledLogger:
    def __init__(self, rate=0.1):
        self._rate = rate; self._count = defaultdict(int)

    def log(self, key, msg, level="info"):
        self._count[key] += 1
        if hash(f"{key}:{self._count[key]}") % 1000 < self._rate * 1000:
            print(f"{level.upper()}: [{key}] {msg}")

    def counts(self): return dict(self._count)

# Escalation policy engine
from dataclasses import dataclass
import time

class Alert:
    def __init__(self, name, severity, created_at=None):
        self.name = name
        self.severity = severity  # 1=critical, 2=warning, 3=info
        self.created_at = created_at or time.time()

@dataclass
class EscalationPolicy:
    name: str
    levels: list  # [(timeout_seconds, notification_target), ...]

class AlertManager:
    def __init__(self):
        self._alerts = {}  # name -> {alert, policy, level_idx, ack}

    def register(self, alert, policy):
        self._alerts[alert.name] = {"alert": alert, "policy": policy,
                                     "level": 0, "ack": None}

    def ack(self, alert_name, by):
        if alert_name in self._alerts:
            self._alerts[alert_name]["ack"] = (by, time.time())

    def resolve(self, alert_name):
        self._alerts.pop(alert_name, None)

    def tick(self):
        now = time.time()
        for name, state in list(self._alerts.items()):
            alert = state["alert"]
            if state["ack"]: continue
            policy = state["policy"]
            elapsed = now - alert.created_at
            while state["level"] < len(policy.levels):
                timeout, target = policy.levels[state["level"]]
                if elapsed >= timeout:
                    print(f"ESCALATE {name} -> {target} (level {state['level']+1})")
                    state["level"] += 1
                else: break

# Incident management tracker
from datetime import datetime

class Incident:
    def __init__(self, severity, summary):
        self.severity = severity
        self.summary = summary
        self.created = datetime.now()
        self.ic = None; self.ops = None; self.comms = None; self.scribe = None
        self.timeline = []  # [(timestamp, who, what), ...]
        self.actions = []
        self.mitigated = None; self.resolved = None
        self.postmortem = {}

    def assign_ic(self, name):
        self.ic = name
        self._log("IC assigned", name)

    def _log(self, what, who):
        self.timeline.append((datetime.now(), who, what))

    def add_mitigation(self, action, by):
        self._log(f"Mitigation: {action}", by)
        self.mitigated = datetime.now()

    def add_resolution(self, action, by):
        self._log(f"Resolution: {action}", by)
        self.resolved = datetime.now()

    def add_action(self, desc, owner, due, severity="P0"):
        self.actions.append({"desc": desc, "owner": owner,
                             "due": due, "severity": severity,
                             "status": "open"})

    def close_action(self, desc):
        for a in self.actions:
            if a["desc"] == desc: a["status"] = "done"; break

    def mt_metrics(self):
        if self.mitigated:
            return (self.mitigated - self.created).total_seconds()
        return None

    def postmortem_write(self, root_cause, impact, contrib):
        self.postmortem = {"root_cause": root_cause,
                           "impact": impact,
                           "contributing": contrib}

# Simple capacity forecasting model
import numpy as np

class CapacityForecast:
    def __init__(self, daily_peak_rps, growth_rate=0.03):
        self.rps = daily_peak_rps
        self.growth = growth_rate  # monthly growth

    def predict(self, months):
        """Return projected monthly peak RPS for N months ahead."""
        return [self.rps * (1 + self.growth)**m for m in range(months+1)]

    def servers_needed(self, rps_target, capacity_per_server, headroom=0.4):
        """Servers needed given headroom fraction (e.g., 0.4 = 40% headroom)."""
        return int(np.ceil(rps_target / (capacity_per_server * (1 - headroom))))

    def plan(self, months, cap_per_server, lead_time_months):
        forecast = self.predict(months)
        full_plan = []
        for m, rps in enumerate(forecast):
            servers = self.servers_needed(rps, cap_per_server)
            order_month = max(0, m - lead_time_months)
            full_plan.append({"month": m, "rps": int(rps),
                              "servers": servers,
                              "order_month": order_month})
        return full_plan

# Usage
plan = CapacityForecast(daily_peak_rps=10000, growth_rate=0.03).plan(12, 500, lead_time_months=2)
for p in plan:
    print(f"Month {p['month']:2d}: {p['rps']:6d} rps -> {p['servers']:3d} servers (order at month {p['order_month']})")

# Progressive rollout controller
import random, time

class Rollout:
    def __init__(self, service, stages):
        self.service = service
        self.stages = stages  # [(pct, duration_min, metric_thresholds), ...]
        self.current = 0

    def run(self):
        for pct, dur, thresholds in self.stages:
            print(f"Rolling to {pct}% for {dur}min")
            self.service.set_traffic_pct(pct)
            time.sleep(dur * 60)
            if not self._check_health(thresholds):
                print(f"ROLLBACK at {pct}%")
                self.service.set_traffic_pct(0)
                return False
            self.current = pct
        return True

    def _check_health(self, thresholds):
        metrics = self.service.get_metrics()
        return all(metrics.get(k) < v for k,v in thresholds.items())

# Feature flag controller
class FeatureFlags:
    def __init__(self, backend):
        self._backend = backend

    def enabled(self, flag, user_pct=100):
        val = self._backend.get(f"flag:{flag}", "off")
        if val == "off": return False
        if val == "on": return True
        if val.startswith("pct:"):
            pct = int(val.split(":")[1])
            return hash(f"{flag}:{user_pct}") % 100 < pct
        return False

    def enable(self, flag, pct=100):
        self._backend.set(f"flag:{flag}", f"pct:{pct}" if pct < 100 else "on")

    def disable(self, flag):
        self._backend.set(f"flag:{flag}", "off")

