# Toil tracking & automation investment calculator
from dataclasses import dataclass

@dataclass
class ToilTask:
    name: str
    freq_weekly: int     # how many times per week
    duration_min: int    # minutes per occurrence
    manual: bool = True

class ToilBudget:
    def __init__(self, team_size=6, eng_days_per_week=4):
        self.tasks = []
        self.team_size = team_size
        # 8h day, 4 eng days/week (excluding on-call, meetings)
        self.total_eng_min_weekly = team_size * eng_days_per_week * 8 * 60

    def add(self, task):
        self.tasks.append(task)

    def toil_minutes(self):
        return sum(t.freq_weekly * t.duration_min for t in self.tasks)

    def toil_pct(self):
        return self.toil_minutes() / self.total_eng_min_weekly * 100

    def automation_roi(self, task, dev_days):
        minutes_saved_weekly = task.freq_weekly * task.duration_min
        dev_minutes = dev_days * 8 * 60
        weeks_to_break_even = dev_minutes / minutes_saved_weekly
        return {"task": task.name,
                "weekly_saved_min": minutes_saved_weekly,
                "breakeven_weeks": weeks_to_break_even}

