# Trace context propagation (W3C TraceContext)
import uuid, time

class Span:
    def __init__(self, trace_id, span_id, parent_id, name):
        self.trace_id = trace_id
        self.span_id = span_id
        self.parent_id = parent_id
        self.name = name
        self.start = time.time()
        self.end = None
        self.tags = {}
        self.children = []

    def finish(self):
        self.end = time.time()

    def duration(self):
        return (self.end or time.time()) - self.start

class Tracer:
    def __init__(self, sample_rate=0.001):
        self._rate = sample_rate

    def should_sample(self):
        return hash(uuid.uuid4()) % 1000 < self._rate * 1000

    def start_span(self, name, parent=None):
        trace_id = parent.trace_id if parent else uuid.uuid4().hex
        span_id = uuid.uuid4().hex
        parent_id = parent.span_id if parent else None
        span = Span(trace_id, span_id, parent_id, name)
        if parent: parent.children.append(span)
        return span

    def inject_headers(self, span):
        return {"traceparent": f"00-{span.trace_id}-{span.span_id}-01"}

    def extract_headers(self, headers):
        tp = headers.get("traceparent", "")
        parts = tp.split("-")
        if len(parts) == 4:
            return Span(parts[1], parts[2], None, "extracted")
        return None

# Exception: structured error with trace context
class TraceError(Exception):
    def __init__(self, msg, span, cause=None):
        self.span = span
        self.cause = cause
        super().__init__(f"{msg} [trace={span.trace_id} span={span.span_id}]")

def handler(req):
    tracer = Tracer()
    span = tracer.start_span("handler")
    headers = tracer.inject_headers(span)
    try:
        resp = downstream_call(headers)
        span.finish()
        return resp
    except Exception as e:
        span.tags["error"] = str(e)
        span.finish()
        raise TraceError("handler failed", span, e) from e

# Backup strategy & testing scheduler
from datetime import datetime, timedelta
import random

class Backup:
    def __init__(self, name, kind, interval, retention):
        self.name = name
        self.kind = kind  # full, incremental, differential
        self.interval = timedelta(**interval)  # e.g. {"hours": 24}
        self.retention = timedelta(**retention)  # e.g. {"days": 30}
        self.backups = []  # [(timestamp, status, size), ...]

    def last_backup(self):
        return self.backups[-1][0] if self.backups else None

    def needs_backup(self):
        last = self.last_backup()
        return not last or (datetime.now() - last) > self.interval

    def perform(self):
        ts = datetime.now()
        ok = random.random() > 0.05  # 95% success rate
        self.backups.append((ts, "ok" if ok else "failed", random.randint(100, 10000)))
        self._prune()
        return ok

    def _prune(self):
        cutoff = datetime.now() - self.retention
        self.backups = [b for b in self.backups if b[0] > cutoff]

class DRPlan:
    def __init__(self, target_rto, target_rpo):
        self.target_rto = timedelta(**target_rto)
        self.target_rpo = timedelta(**target_rpo)
        self.backups = {}; self.tests = []

    def add_backup(self, backup):
        self.backups[backup.name] = backup

    def check_readiness(self):
        last_full = next((b.last_backup() for b in self.backups.values()
                          if b.kind == "full"), None)
        if not last_full: return False
        age = datetime.now() - last_full
        return age < self.target_rpo

    def schedule_test(self):
        test = {"date": datetime.now() + timedelta(days=random.randint(1, 90)),
                "type": random.choice(["tabletop", "partial", "full"]),
                "status": "scheduled"}
        self.tests.append(test)
        return test

# Multi-window burn rate alert evaluation
from datetime import datetime, timedelta

class BurnRateAlerts:
    # Google SRE Workbook standard windows
    WINDOWS = [
        {"name": "fast", "window_h": 2,  "rate": 14.4, "severity": "critical"},
        {"name": "medium", "window_h": 6,  "rate": 6.0, "severity": "warning"},
        {"name": "slow", "window_h": 72, "rate": 1.0, "severity": "ticket"},
    ]

    def evaluate(self, error_rate, slo):
        allowed_bad = 1 - slo/100
        actual_bad = error_rate / 100
        burn_rate = actual_bad / allowed_bad if allowed_bad > 0 else float("inf")

        alerts = []
        for w in self.WINDOWS:
            threshold = w["rate"]
            if burn_rate >= threshold:
                alerts.append({
                    "name": f"burn_{w['name']}",
                    "severity": w["severity"],
                    "burn_rate": round(burn_rate, 2),
                    "message": f"Burn rate {burn_rate:.1f}x > {threshold}x ({w['name']} burn)"
                })
        return alerts

    def time_to_budget_depletion(self, budget, slo):
        allowed_bad = 1 - slo/100
        remaining = allowed_bad - budget.consumed()
        if remaining <= 0: return timedelta(0)
        burn_rate = budget.burn_rate()
        if burn_rate <= 0: return timedelta(days=365)
        return timedelta(seconds=remaining / burn_rate * budget.window.total_seconds())

