from dataclasses import dataclass

@dataclass
class PRRChecklist:
    service: str; owner: str

    checks = {
        "Monitoring": [
            "SLI defined for latency, error rate, saturation",
            "Dashboard exists and linked from runbook",
            "Alerts configured with correct severity",
        ],
        "On-call": [
            "Runbook written and tested",
            "Team trained on service",
            "Escalation policy defined",
        ],
        "Capacity": [
            "Load test passed at 2x peak traffic",
            "Auto-scaling configured and tested",
            "Quota limits set for all dependencies",
        ],
        "Deployment": [
            "Canary stages defined (1-5-25-100%)",
            "Rollback tested",
            "Feature flags for all new features",
        ],
        "DR": [
            "RTO/RPO defined",
            "Backup verified (restore tested)",
            "Failover tested",
        ],
    }

    def __post_init__(self):
        self.results = {cat: {c: False for c in checks}
                        for cat, checks in self.checks.items()}

    def pass_item(self, category, check):
        if category in self.results and check in self.results[category]:
            self.results[category][check] = True

    def pass_pct(self):
        total = sum(len(c) for c in self.results.values())
        passed = sum(sum(1 for v in c.values() if v) for c in self.results.values())
        return passed / total * 100

    def is_ready(self):
        return self.pass_pct() >= 100.0

    def report(self):
        rows = []
        for cat, checks in self.results.items():
            for check, passed in checks.items():
                rows.append([cat, check, "PASS" if passed else "FAIL"])
        return rows

# GSLB with health-based failover
from dataclasses import dataclass
import time

@dataclass
class PoolMember:
    host: str; region: str; healthy: bool = True
    last_check: float = 0; failures: int = 0

class GSLBPool:
    def __init__(self, name, ttl=30, health_check_interval=10):
        self.name = name; self.ttl = ttl
        self.hc_interval = health_check_interval
        self.members = []

    def add(self, host, region):
        self.members.append(PoolMember(host=host, region=region))

    def check_health(self, check_fn):
        now = time.time()
        for m in self.members:
            if now - m.last_check >= self.hc_interval:
                m.healthy = check_fn(m.host)
                m.last_check = now
                m.failures = 0 if m.healthy else m.failures + 1

    def resolve(self, client_region=None):
        healthy = [m for m in self.members if m.healthy]
        if not healthy: return []  # return nothing -> fail open or serve stale
        if client_region:
            regional = [m for m in healthy if m.region == client_region]
            if regional: return regional
        return healthy

    def best_for_geo(self, client_region):
        pool = self.resolve(client_region)
        return pool[0].host if pool else None

# DNS stub with TTL management
class DNSRecord:
    def __init__(self, name, pool, ttl=30):
        self.name = name; self.pool = pool; self.ttl = ttl
        self.cached = None; self.cached_at = 0

    def lookup(self, client_region):
        now = time.time()
        if self.cached and now - self.cached_at < self.ttl:
            return self.cached, "cached"
        self.cached = self.pool.best_for_geo(client_region)
        self.cached_at = now
        return self.cached, "resolved"

# Terraform-like state management (simplified)
import json, hashlib

class StateFile:
    def __init__(self, backend):
        self._backend = backend  # could be s3, local file, etcd
        self._resources = {}
        self._lock = False

    def load(self):
        raw = self._backend.read()
        if raw:
            data = json.loads(raw)
            self._resources = data.get("resources", {})

    def save(self):
        self._backend.write(json.dumps({"resources": self._resources,
                                         "serial": self._serial()}))

    def _serial(self):
        return hashlib.md5(json.dumps(self._resources, sort_keys=True).encode()).hexdigest()

    def lock(self, owner):
        if self._lock: raise RuntimeError(f"Locked by {self._lock}")
        self._lock = owner; return True

    def unlock(self, owner):
        if self._lock != owner: raise RuntimeError("Not lock owner")
        self._lock = False

    def resource(self, addr):
        return self._resources.get(addr)

    def set_resource(self, addr, attrs):
        self._resources[addr] = attrs

    def remove_resource(self, addr):
        self._resources.pop(addr, None)

    def plan_diff(self, desired):
        added = [k for k in desired if k not in self._resources]
        removed = [k for k in self._resources if k not in desired]
        changed = [k for k in desired if k in self._resources
                   and self._resources[k] != desired[k]]
        return {"add": added, "remove": removed, "change": changed}

# Cost & efficiency analyzer
from dataclasses import dataclass

@dataclass
class Resource:
    name: str; instance_type: str; hourly_cost: float
    cpu_pct: float; mem_pct: float; running: bool

class CostAnalyzer:
    def __init__(self):
        self.resources = []

    def add(self, r):
        self.resources.append(r)

    def monthly_cost(self):
        return sum(r.hourly_cost * 730 for r in self.resources if r.running)

    def waste_report(self, cpu_thresh=20, mem_thresh=20):
        waste = []
        for r in self.resources:
            if r.running and r.cpu_pct < cpu_thresh and r.mem_pct < mem_thresh:
                waste.append({"name": r.name, "type": r.instance_type,
                              "monthly_waste": r.hourly_cost * 730,
                              "reason": f"CPU {r.cpu_pct}% < {cpu_thresh}%, "
                                        f"Mem {r.mem_pct}% < {mem_thresh}%"})
        return waste

    def savings_recommendations(self):
        recs = []
        # Right-sizing suggestions
        for r in self.resources:
            if r.cpu_pct < 20 and r.mem_pct < 20:
                recs.append({"resource": r.name,
                             "action": "Downsize or terminate",
                             "savings_pct": 50})
        return recs

    def cost_by_tag(self, tag_key):
        groups = {}
        from collections import defaultdict
        costs = defaultdict(float)
        for r in self.resources:
            groups.setdefault(r.instance_type, 0)
            groups[r.instance_type] += r.hourly_cost * 730
        return groups

